Here's a modern MSTest test class for `DataFetcher`:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("hello world"),
            });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.NotFound));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        // Arrange
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // pre-cancel
        var handler = new FakeHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)]
    public async Task FetchAsync_RespectsTestContextCancellationToken()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(
            new HttpResponseMessage(HttpStatusCode.OK)
            {
                Content = new StringContent("with timeout"),
            });
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act — passes TestContext.CancellationToken so [Timeout] can abort the call
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        // Assert
        Assert.AreEqual("with timeout", result);
    }

    [TestMethod]
    [DataRow(HttpStatusCode.InternalServerError)]
    [DataRow(HttpStatusCode.ServiceUnavailable)]
    [DataRow(HttpStatusCode.Forbidden)]
    public async Task FetchAsync_ErrorStatusCode_Throws(HttpStatusCode statusCode)
    {
        // Arrange
        var handler = new FakeHttpMessageHandler(
            new HttpResponseMessage(statusCode));
        var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act & Assert
        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    /// <summary>Minimal handler that returns a canned response.</summary>
    private sealed class FakeHttpMessageHandler(HttpResponseMessage response)
        : HttpMessageHandler
    {
        protected override Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            cancellationToken.ThrowIfCancellationRequested();
            return Task.FromResult(response);
        }
    }
}
```

**Key patterns used:**

| Pattern | How |
|---|---|
| **Sealed class** | `public sealed class` — better perf & design clarity |
| **Constructor-injected TestContext** | Gives access to `_testContext.CancellationToken` |
| **Async exceptions** | `Assert.ThrowsExactlyAsync<T>` — exact type match, no `[ExpectedException]` |
| **Timeout + cancellation** | `[Timeout(5000)]` + `_testContext.CancellationToken` — the token is auto-cancelled when the timeout fires |
| **Data-driven error codes** | `[DataRow]` parameterizes multiple HTTP status codes |
| **Fake handler** | `FakeHttpMessageHandler` avoids real network calls and respects `CancellationToken` |

The critical detail: `[Timeout]` works by cancelling `TestContext.CancellationToken`, so you **must** pass that token into your async calls for the timeout to actually abort them.
